  ($c$valid-parentheses$c$, $c$Valid Parentheses$c$, $c$Write a function `isValid(s)` that determines if the input string `s` — containing only `(`, `)`, `{`, `}`, `[`, `]` — has every open bracket closed by the same type in the correct order.
Return a boolean.$c$, $c$speed_build$c$, $c$code_duel$c$, $c$medium$c$, 20, $c$javascript$c$, $c$function isValid(s) {
  // Your code here
}$c$, $c$function isValid(s) {
  var stack = [];
  var map = { ")": "(", "}": "{", "]": "[" };
  for (var i = 0; i < s.length; i++) {
    var c = s[i];
    if (c === "(" || c === "{" || c === "[") {
      stack.push(c);
    } else {
      if (stack.pop() !== map[c]) return false;
    }
  }
  return stack.length === 0;
}$c$, $j$[{"label":"simple parens valid","input":"\"()\"","expected":"true"},{"label":"all types valid","input":"\"()[]{}\"","expected":"true"},{"label":"mismatched","input":"\"(]\"","expected":"false"},{"label":"interleaved invalid","input":"\"([)]\"","expected":"false"},{"label":"nested valid","input":"\"{[]}\"","expected":"true"},{"label":"empty string","input":"\"\"","expected":"true"},{"label":"unclosed","input":"\"(((\"","expected":"false"}]$j$::jsonb, NULL, false),
