  ($c$binary-search$c$, $c$Binary Search$c$, $c$Write a function `binarySearch(arr, target)` that searches a sorted array for `target` and returns its index, or `-1` if not found.
Use an iterative binary search. O(log n) expected.$c$, $c$speed_build$c$, $c$code_duel$c$, $c$hard$c$, 30, $c$javascript$c$, $c$function binarySearch(arr, target) {
  // Your code here
}$c$, $c$function binarySearch(arr, target) {
  var lo = 0, hi = arr.length - 1;
  while (lo <= hi) {
    var mid = (lo + hi) >> 1;
    if (arr[mid] === target) return mid;
    if (arr[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}$c$, $j$[{"label":"found middle","input":"[1,2,3,4,5], 3","expected":"2"},{"label":"found first","input":"[1,2,3,4,5], 1","expected":"0"},{"label":"found last","input":"[1,2,3,4,5], 5","expected":"4"},{"label":"not found","input":"[1,2,3,4,5], 6","expected":"-1"},{"label":"single element found","input":"[7], 7","expected":"0"},{"label":"single element missing","input":"[7], 3","expected":"-1"},{"label":"empty array","input":"[], 5","expected":"-1"}]$j$::jsonb, NULL, false),
