  // Your code here
}$c$, $c$function productExceptSelf(nums) {
  var n = nums.length;
  var result = [];
  var i;
  for (i = 0; i < n; i++) result[i] = 1;
  var prefix = 1;
  for (i = 0; i < n; i++) {
    result[i] = prefix;
    prefix *= nums[i];
