</html>$c$, $c$<!DOCTYPE html>
<html>
<head>
<style>
  body { margin:0; min-height:100vh; display:flex; align-items:center; justify-content:center; background:#0a0a0f; font-family:system-ui,sans-serif; color:white; }
  .card { background:#ffffff; color:#111827; border-radius:16px; box-shadow:0 8px 32px rgba(0,0,0,0.5); padding:32px 28px; width:300px; display:flex; flex-direction:column; gap:12px; }
  .plan { font-size:14px; font-weight:600; text-transform:uppercase; letter-spacing:.08em; color:#6366f1; }
  .price { font-size:48px; font-weight:700; line-height:1; }
  .price span { font-size:18px; font-weight:400; color:#6b7280; }
  .desc { color:#6b7280; font-size:14px; }
  .btn { margin-top:8px; background:#6366f1; color:#fff; border:none; border-radius:8px; padding:12px; font-size:16px; font-weight:600; cursor:pointer; }
</style>
</head>
<body>
  <div class="card">
    <div class="plan">Pro</div>
    <div class="price">$29<span>/mo</span></div>
    <div class="desc">Everything you need to ship faster.</div>
    <button class="btn">Get started</button>
  </div>
</body>
</html>$c$, $j$[{"label":"has a card/container element with a light background","input":"!!(document.querySelector('[style*=\"background:#fff\"]') || document.querySelector('[style*=\"background: #fff\"]') || document.querySelector('[style*=\"background:#ffffff\"]') || document.querySelector('[style*=\"background: #ffffff\"]') || document.querySelector('[style*=\"background:#f9fafb\"]') || (()=>{ const el = document.querySelector('.card') || document.querySelector('[class]'); return el && getComputedStyle(el).backgroundColor !== 'rgba(0, 0, 0, 0)' && getComputedStyle(el).backgroundColor !== 'rgb(10, 10, 15)'; })())","expected":"\"true\""},{"label":"has a price element displaying a dollar amount","input":"document.body.innerHTML.includes('$') && (document.body.innerHTML.includes('/mo') || document.body.innerHTML.includes('/month') || document.body.innerHTML.includes('mo'))","expected":"\"true\""},{"label":"has at least one button","input":"document.querySelectorAll('button').length > 0 || document.querySelectorAll('a[class*=\"btn\"]').length > 0 || document.querySelectorAll('[role=\"button\"]').length > 0","expected":"\"true\""},{"label":"button uses indigo colour (#6366f1)","input":"document.body.innerHTML.includes('6366f1') || document.body.innerHTML.includes('99, 102, 241') || document.body.innerHTML.includes('6366F1')","expected":"\"true\""},{"label":"card has rounded corners","input":"document.body.innerHTML.includes('border-radius') || document.body.innerHTML.includes('rounded')","expected":"\"true\""},{"label":"has a plan name or heading text","input":"!!(document.querySelector('h1') || document.querySelector('h2') || document.querySelector('h3') || document.querySelector('.plan') || document.body.innerHTML.toLowerCase().includes('pro') || document.body.innerHTML.toLowerCase().includes('plan'))","expected":"\"true\""}]$j$::jsonb, NULL, false),
  ($c$toggle-switch$c$, $c$Build the Toggle Switch$c$, $c$Create a styled toggle switch UI centred on a dark (#0a0a0f) page.
The toggle should visually resemble a pill-shaped track (width ~48px, height ~26px) with a circular thumb inside it.
Show TWO states side by side or stacked: one toggle in the OFF state (grey track, #4b5563) and one toggle in the ON state (indigo track, #6366f1, thumb on the right).
