<html>
<head>
<style>
  body { margin:0; min-height:100vh; display:flex; flex-direction:column; align-items:center; justify-content:center; gap:24px; background:#0a0a0f; font-family:system-ui,sans-serif; color:white; }
  .toggle-row { display:flex; align-items:center; gap:12px; }
  .track { width:48px; height:26px; border-radius:999px; position:relative; transition:background .2s; }
  .track.off { background:#4b5563; }
  .track.on { background:#6366f1; }
  .thumb { width:20px; height:20px; border-radius:50%; background:#fff; position:absolute; top:3px; transition:left .2s; }
  .track.off .thumb { left:3px; }
  .track.on .thumb { left:25px; }
  .label { font-size:14px; color:#d1d5db; }
</style>
</head>
<body>
  <div class="toggle-row">
    <div class="track off"><div class="thumb"></div></div>
    <span class="label">Notifications off</span>
  </div>
  <div class="toggle-row">
    <div class="track on"><div class="thumb"></div></div>
    <span class="label">Notifications on</span>
  </div>
</body>
</html>$c$, $j$[{"label":"has at least two toggle track elements","input":"(document.querySelectorAll('.track').length >= 2) || (document.querySelectorAll('[style*=\"border-radius: 999px\"]').length >= 2) || (document.querySelectorAll('[style*=\"border-radius:999px\"]').length >= 2) || (document.querySelectorAll('[style*=\"border-radius: 9999px\"]').length >= 2) || (document.querySelectorAll('input[type=\"checkbox\"]').length >= 2)","expected":"\"true\""},{"label":"has a circular thumb element","input":"!!(document.querySelector('.thumb') || document.querySelector('[style*=\"border-radius: 50%\"]') || document.querySelector('[style*=\"border-radius:50%\"]'))","expected":"\"true\""},{"label":"uses indigo colour for on-state track","input":"document.body.innerHTML.includes('6366f1') || document.body.innerHTML.includes('99, 102, 241') || document.body.innerHTML.includes('6366F1') || document.body.innerHTML.includes('indigo')","expected":"\"true\""},{"label":"uses a grey colour for the off-state track","input":"document.body.innerHTML.includes('4b5563') || document.body.innerHTML.includes('6b7280') || document.body.innerHTML.includes('9ca3af') || document.body.innerHTML.includes('gray') || document.body.innerHTML.includes('grey')","expected":"\"true\""},{"label":"has label text for the toggles","input":"document.body.innerText.trim().length > 5","expected":"\"true\""}]$j$::jsonb, NULL, false),
