Constraints: no heavy UI frameworks — plain HTML/CSS, Tailwind, or lightweight CSS-in-JS only.$c$, $c$speed_build$c$, $c$url_submit$c$, $c$easy$c$, 25, $c$javascript$c$, NULL, NULL, NULL, NULL, false),
